The following index definition for the `sample_training.companies`
namespace indexes the array of objects in the `products` field. It also
configures MongoDB Search to automatically index all dynamically indexable fields
inside the objects in the `products` array.

```csharp
using MongoDB.Bson;
using MongoDB.Driver;

// Replace the connection string with your MongoDB deployment's connection string
var uri = "<connection-string>";

var client = new MongoClient(uri);

var db = client.GetDatabase("sample_supplies");
var collection = db.GetCollection<BsonDocument>("sales");

// Create the MongoDB Search index definition for the embeddedDocuments field
var index =  new CreateSearchIndexModel(
  "default", new BsonDocument
  {
    { "mappings", new BsonDocument
      {
        { "dynamic", false },
        { "fields", new BsonDocument
          {
            { "items", new BsonDocument
              {
                { "type", "embeddedDocuments" },
                { "dynamic", true }
              }
            }
          }
        }
      }
    }
  });

var result = collection.SearchIndexes.CreateOne(index);
Console.WriteLine($"New index name: {result}");
